var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"덕분에 살았군. 이건 기억해 두지.","JPN":"おかげで助かったよ、この恩は覚えておこう。","ENG":"I guess I owe you my life. I'll remember that.","TWN":"多虧你們，我才活了下來，我會記住的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"별말씀을.","JPN":"どういたしまして。","ENG":"It was our pleasure.","TWN":"這沒什麼。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"의뢰인이 위험에 처했으면 당연히 도와드려야지.","JPN":"依頼人が危険にさらされたら、当然助けるさ。","ENG":"It's my job to help when you're in danger.","TWN":"委託人遇到危險的話，我們當然要幫忙了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......자네에게 한 말 아닐세, 메이슨.","JPN":"……お前に言ったんじゃないぞ、メイソン。","ENG":"I wasn't talking to you, Mason...","TWN":"……這不是對你說的，梅森。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"말이 나와서 말인데, 정보를 캐라고 보내놨더니 붙잡힌 공주님 신세나 되고, 그게 무슨 개망신인가?","JPN":"頼んだ情報を手に入れるところか、奴らに捕まるなんてな。情けないにもほどがある。","ENG":"If anything, you ended up getting captured like a damsel in distress when I sent you to collect intel. How embarrassing is that?","TWN":"我派你去收集情報，結果你卻成了被綁架的公主，這是在搞什麼啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"여기 숙녀 분들이 도와주지 않았다면 강가에서 변사체 같은 걸로 발견되었을 텐데.","JPN":"こちらのレディーたちが助けてくれなければ、川辺で変死体として見つかったんだろうな。","ENG":"If it weren't for these ladies, you'd be nothing more than a cold corpse by now.","TWN":"要不是這裡的淑女們救了你，你說不定就變成河邊的一具特異體屍體了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......의뢰인 씨. 원래 현장이라는 게 꼭 예정대로 돌아가는 건 아니라고.","JPN":"……依頼人よ、現場ってもんはな、いつも予定通りまわるとは限らないんだ。","ENG":"My dear client... Things don't always go as expected in the field, you know.","TWN":"……委託人，現場人員不代表他一定能按原定計劃返回。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"자네에 대한 나의 신뢰도는 매우 예정대로 추락하고 있네.","JPN":"そうか、お前に対する俺の信頼度は予定どおり右肩下がりだな。","ENG":"Well, my trust in you sure is plummeting, as expected.","TWN":"我對你的信任，也正按原定計劃急速下降……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니, 그래도 고생해서 여기까지 구하러 왔는데 말이야.......","JPN":"苦労してここまで助けにきてやったのに……","ENG":"After everything I've been through to come save you...","TWN":"不，可是我都為了救你來到這裡了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"칭찬 정도는 해 줘도 되잖아.......","JPN":"褒めてくれたっていいじゃないか……","ENG":"You could at least give me a pat on the back.","TWN":"你就不能稱讚我一下嗎……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 소리는 됐어.","JPN":"無駄話はこの辺にしよう。","ENG":"That's enough.","TWN":"廢話就算了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 여기서 무슨 일이 벌어지고 있는 건지 설명해 줘.","JPN":"それより、ここで何が起きているのか教えてほしい。","ENG":"Now... Can you please tell us what's going on here?","TWN":"比起這個，你給我解釋一下這裡發生了什麼事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 정도는 우리도 들을 자격이 있다고 생각하는데?","JPN":"それくらいは私たちも聞く権利があると思うけど？","ENG":"I think we deserve to hear an explanation.","TWN":"這些事情，我們也有資格聽吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......물론이지.","JPN":"……もちろんだ。","ENG":"Why, of course.","TWN":"……那當然！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그전에 우선 내 소개부터 해야겠군.","JPN":"その前に、自己紹介をしよう。","ENG":"Let me introduce myself first.","TWN":"那在此之前我得先自我介紹一下。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"내 이름은 마크 핀리.","JPN":"俺の名前は、マーク・フィンリー。","ENG":"My name is Mark Finley.","TWN":"我的名字叫馬克·芬利。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"일단은 민간군사기업인 핀리 하이어드의 사장이지. 잘 부탁하네.","JPN":"一応、民間軍事企業であるフィンリー・ハイアードの社長だ。よろしく頼む。","ENG":"I'm the President of Finley Hired, a private military company. It's a pleasure to meet you all.","TWN":"目前是民間軍事企業芬利傭兵團的老闆，請多多指教。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......당신이 그 회사 사장이라고?","JPN":"……あなたがあの会社の社長だって？","ENG":"...You're the president of the company?","TWN":"……你說你是那家公司的老闆？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"최최최최종 보스가 이런 데 왜 있는 거죠!?","JPN":"そんなラスボスがなぜこんなところにいるんですか？！","ENG":"But that means you're like, the ultimate final boss. What are you doing here?!","TWN":"最最最最大的魔王為什麼在這裡呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히이이.......","JPN":"ひいいっ……","ENG":"*Gasp*","TWN":"哇啊啊……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"......그치만 아저씨는 도시에서 본 용병들이랑 분위기가 좀 다른데요?","JPN":"……だけど、マークさんは都市で見かけた傭兵とは若干雰囲気が違いますね。","ENG":"Still, I'm getting a different vibe from you than those mercenaries in the city...","TWN":"……不過，我們和大叔在城裡看到的傭兵們，和你的氛圍有點不一樣耶？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"애초에 같은 편이었다면 이런 곳에서 습격당했을 리도 없고.......","JPN":"そもそも味方ならこんなところで襲撃されるはずないし……","ENG":"And you wouldn't have gotten ambushed if you were on the same side...","TWN":"如果當初就說是自己人的話，我們就不會在那個地方被襲擊了吧……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이해력이 좋군, 아가씨.","JPN":"君は頭の回転が早いな。","ENG":"You're very sharp, young lady.","TWN":"小姐，妳的理解力真好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"핀리 하이어드는 본래 랭글리의 위장 기업인 핀리 컴퍼니의 자회사들 중 하나야.","JPN":"フィンリー・ハイアードは、元々ラングレーの偽装企業であるフィンリーカンパニーの子会社の1つだ。","ENG":"Finley Hired is actually one of the affiliates of Finley Company, a front organization set up by Langley.","TWN":"芬利傭兵團呢，本來也是蘭格利的偽裝企業，芬利公司的子公司之一。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"나 역시 랭글리에서 파견된 관리직이고.","JPN":"俺もラングレーから出向中の管理職でな。","ENG":"I was an administrator who was deployed from Langley.","TWN":"而我本來也是蘭格利派來的管理人員。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"랭글리?","JPN":"ラングレー？","ENG":"Langley?","TWN":"蘭格利？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"C, CIA의 별명이에요. 잠입 게임 같은 데서 본 적이 있어요.","JPN":"C, CIAの別名です。潜入ゲームなどで見たことがあります。","ENG":"T-that's a nickname for the CIA. I think I saw it in one of those stealth games.","TWN":"是、是CIA的別稱。我在間諜遊戲中有看過。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"잘 알고 있군.","JPN":"なかなか詳しいんだな。","ENG":"Yes, that's correct.","TWN":"真虧妳知道呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그 말대로 핀리 하이어드는 꽤 괜찮은 위장조직이었지.","JPN":"その通りだ。フィンリー・ハイアードは結構イケイケの偽装組織だった。","ENG":"Finley Hired served as a pretty decent front organization.","TWN":"如同她說的一樣，芬利傭兵團是一個優秀的偽裝組織。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그러니까, 원래는 그랬다는 말이야.","JPN":"元々はそうだった、という話だが。","ENG":"Note the past tense there.","TWN":"嗯，本來應該是這樣的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"하지만 내 전임 관리자였던 어떤 얼간이가 우리를 배신하고 저 테러리스트 조직에 가담하는 바람에 문제가 발생하기 시작했네.","JPN":"俺の前任者だったあるマヌケ野郎が俺たちを裏切って、あのテロリスト組織に加担したところから問題が発生したんだ。","ENG":"But the problems came when my predecessor betrayed us and joined forces with that terrorist organization.","TWN":"但是我的前任管理者——某個笨蛋，他背叛了我們，並加入了那個恐怖份子組織，所以才開始逐漸出現問題。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그 후에 여러 가지 복잡한 과정을 거쳐서 그 작자를 숙청하긴 했지만.......","JPN":"それ以降、色々込み入った過程を経て、そいつの粛清には成功したがな……","ENG":"Although we purged the company of him through a series of complicated procedures...","TWN":"此後，經歷了種種複雜的事件，雖然肅清了那個傢伙，但……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그 과정에서 우리도 꽤 큰 타격을 받았어.","JPN":"その過程の中で、俺らも大打撃を食らってしまったんだ。","ENG":"We were still hit pretty hard in the process.","TWN":"在這個過程中，我們也遭受了很大的打擊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"나는 그 뒷수습을 위해 배치됐고 조직 내에 아직 남아있을지도 모르는 배신자들을 색출하기 위해 이 친구를 고용했지만.......","JPN":"俺はその後片付けのために配置されてな、組織内の残党を洗い出すためにこいつを雇用したのだが……","ENG":"I was assigned to clean up the mess and I hired this guy to track down any traitors that might still be in the organization...","TWN":"為了善後，我被安排到了組織內部。然後為了查出可能還活著的叛徒，所以我雇用了這位朋友。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"보다시피 놈들이 한 발 더 빨랐지.","JPN":"見てのとおり、奴らのほうが一歩早かった。","ENG":"But they were one step ahead of me, as you can see.","TWN":"但如你們所見，這些傢伙又快我一步。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"핀리 하이어드는 이미 뿌리 끝까지 <color=#ffd34c>리플레이서</color> 놈들에게 장악당해 있었으니까.","JPN":"フィンリー・ハイアードはすでに根元まで<color=#ffd34c>リプレイサー</color> の奴らに掌握されていたからな。","ENG":"Finley Hired had already become dominated by the <color=#ffd34c>Replacers</color> down to the deepest reaches of the organization.","TWN":"芬利傭兵團已經完完全全被<color=#ffd34c>克隆集團</color>掌控了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......리플레이서?","JPN":"……リプレイサー？","ENG":"...Replacers?","TWN":"……克隆集團。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그래, 통칭 리플레이서 신디케이트.","JPN":"そうだ、通称リプレイサー・シンジケート。","ENG":"Yes, also known as the Replacer Syndicate.","TWN":"是的，全名稱為“克隆者集團企業”。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"너희들을 공격하고 도시를 점거한 테러리스트 조직의 이름이다.","JPN":"お前らを攻撃して都市を占拠したテロリスト組織の名前だ。","ENG":"That's the terrorist organization that attacked you guys and took over the city.","TWN":"這就是襲擊你們，並且佔領你們城市的恐怖組織名字。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"가, 갑자기 스케일이 엄청 커진 것 같은데 기분 탓이겠죠......?","JPN":"きゅ、急激にスケールがすごく大きくなった気がしますが、気のせいですよね……？","ENG":"I feel like I'm in way over my head right now...","TWN":"事、事件的規模好像突然變得很大，是我的錯覺嗎……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"스케일은 이미 도시를 탈출했을 때부터 충분히 컸다고요.......","JPN":"スケールは、都市から脱出したところで十分大きかったですよ……","ENG":"Things were already getting out of hand when we were escaping the city...","TWN":"早在逃離城市的時候，事件規模就已經變得很大了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그 녀석들이 테러리스트라는 건 알겠어.","JPN":"……そいつらがテロリストだというのはわかった。","ENG":"...I can see how those guys are terrorists.","TWN":"……我知道他們都是恐怖份子了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨들과 복잡한 사연이 있다는 것도 이해했고.","JPN":"マークさんたちとの複雑な事情があるのも理解したし。","ENG":"And I understand that you guys have a complicated relationship.","TWN":"也理解了他們和大叔們有錯綜複雜的過去。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만...... 대체 도시를 습격한 건 뭣 때문이야?","JPN":"だけど……都市を襲ったのは何のため？","ENG":"But... But why on earth would they want to attack the city?","TWN":"但是……他們襲擊城市的原因又是什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"테러리스트라는 건 폭탄이나 터트리고 다니는 녀석들인 줄 알았는데......?","JPN":"テロリストって、爆弾とかを仕掛けるような奴らだと思ってたのに……","ENG":"I thought terrorists used bombs and stuff like that...?","TWN":"我印象中的恐怖份子，應該是那種會到處扔炸彈的傢伙啊……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"거기에 대해선 내가 설명해 주지.","JPN":"それについては俺から説明しよう。","ENG":"I can explain that part.","TWN":"我來回答這個問題吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"애초에 내가 KS-1 도시관리국에 잠입한 게 놈들의 목적을 알아내기 위해서였으니까.","JPN":"元々俺がKS-1都市管理局に潜入した目的は、奴らの目的を調べるためだったからな。","ENG":"The reason why I infiltrated the KS-1 City Managements in the first place was to figure out what those guys were after.","TWN":"當初我潛入KS-1的城市管理局，就是為了瞭解這些傢伙的目的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그래서 그 목적이란 게 뭔데?","JPN":"……それで、その目的は何？","ENG":"And...? What did you find out?","TWN":"……所以，他們的目的是什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"간단해.","JPN":"とてもシンプルさ。","ENG":"It's simple.","TWN":"其實很簡單。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"리플레이서 놈들의 목적은 인간과 침식체의 융합체로 이루어진 군대를 만드는 거다.","JPN":"リプレイサー野郎の目的は、人間と侵食体の融合体で軍隊を作ることなんだ。","ENG":"The goal of those Replacers is to combine humans and C.O.s to create an army of hybriders.","TWN":"克隆集團的那些傢伙的目的呢，就是打造一支由人類與侵蝕體的融合體所組成的軍隊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭣......?","JPN":"なっ……？","ENG":"What...?","TWN":"什麼……?！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"너희도 상대해 봐서 알겠지만 융합체란 건 꽤 매력적인 소재지.","JPN":"君らも戦ってみてわかったと思うが、融合体というのはかなり魅力的な素材でな。","ENG":"As you could tell while fighting them, hybriders make ideal soldiers.","TWN":"你們親自跟它們交手過也會知道，融合體其實是非常有魅力。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"인간을 초월하는 신체 능력에, 침식체에 맞먹는 강력한 내구도.","JPN":"人間を越える身体能力に、侵食体に匹敵する強力な耐久度。","ENG":"On top of their superhuman strength, they're almost as resilient as C.O.s.","TWN":"他們有著超越人類的身體能力，和能與侵蝕體匹敵的強大耐久度。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......거기다가 인간의 장비를 사용하고 명령까지 내릴 수 있으니 일반 병사들과는 애초에 비교가 불가능해.","JPN":"……それに人間の装備を使用したり命令することも可能だから、一般の兵士たちとは最初から比べ物にならないんだ。","ENG":"Plus, they can use human gear and follow orders, making them incomparable to ordinary human soldiers.","TWN":"……而且他們還可以使用人類的裝備，甚至完全服從命令。相較之下，普通士兵根本不可能做到。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그렇군...... 그래서 KS-1 같은 대도시를 원한 거군.","JPN":"なるほど……だからKS-1のような大都市を狙ったわけだ。","ENG":"I see... So that's why they want a major city like KS-1.","TWN":"是啊……所以他們才想要KS-1這樣的大城市。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"맞아. 바로 그런 이유 때문이지.","JPN":"その通りだ。そんな理由があったんだ。","ENG":"Precisely. That's exactly why.","TWN":"對，就是這樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저, 저기요? 제가 대화를 못 따라가겠는데요......?","JPN":"あ、あのう？　会話についていけないのですが……？","ENG":"U-um... Excuse me? I'm not sure if I follow...?","TWN":"呃，那個，是我跟不上大家的對話嗎……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그래요. 그거랑 리플레이서가 도시를 점령한 게 무슨 상관이죠?","JPN":"そ、そうです。それとリプレイサーが都市を占領したのに何の関係があるんですか？","ENG":"Y-yeah. What's that got to do with how the Replacers are taking over the city?","TWN":"對、對啊，那和克隆集團佔領城市又有什麼關係呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"간단해. 융합체 군대를 만들려면 제일 필요한 게 뭐지?","JPN":"簡単だよ。融合体の軍隊を作るには、何が一番必要だろうか？","ENG":"It's simple. To create a hybrider army, what's the first thing you'd need?","TWN":"很簡單。如果妳想要建立融合體軍隊的話，最需要的東西什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 글쎄요......? 간식...... 아닐까요? 괴물 군대도 간식은 먹어야 하니까......","JPN":"さ、さあ……？　おやつ……ですかね？　化け物の軍隊でもおやつは必要でしょうから……","ENG":"Um... I'm not sure? Snacks... Right? Since monster soldiers need to eat snacks, too...","TWN":"這個……零食吧？怪物軍隊也得吃零食啊……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"바보 같은 소리 하지 마세요! 괴물이 무슨 간식을 먹어요?!","JPN":"バカ言わないでください！　化け物がおやつなんて食べるもんですか！？","ENG":"Don't be absurd! Monsters don't need snacks!","TWN":"別說傻話啦！！ 怪物吃什麼零食啦！？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"영화를 보면 이런 경우엔 대부분 돈이 목적이에요.","JPN":"映画でこういう場合は、だいたい金目当てですよ。","ENG":"It's all about the money. At least according to the movies...","TWN":"在電影中這種劇情很常見，大部分都是為了錢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"괴물 용병도 월급은 받아야 하니까......","JPN":"化け物の傭兵だって、お給料は欲しいでしょうから……","ENG":"Because monster soldiers need to get paid, too!","TWN":"因為怪物傭兵也要拿薪水啊……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"도시 금고를 털어서 괴물 용병에게 줄 월급을 조달하려던 게 분명해요!","JPN":"都市中の金庫から、化け物の傭兵へのお給料を調達しようとしたに違いないです！","ENG":"They're going to rob the city vault and use the money to pay the monster soldiers! That's it!","TWN":"很明顯，他們想攻進都市的金庫，來籌集給怪物傭兵們的薪水！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니, 그건...... 영화를 너무 많이 본 것 같은데......","JPN":"いや、それは……映画の観すぎじゃないか……","ENG":"No, that's... I think you've been watching too many movies...","TWN":"不，那個……妳電影好像看太多了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......재료로군.","JPN":"……材料ね。","ENG":"They're after... the ingredients.","TWN":"……是原料吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......딩동댕. 정답이야.","JPN":"……ピンポーン！　正解だ。","ENG":"Bingo. Exactly.","TWN":"……叮咚，正確答案！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"융합체를 만들려면 어쨌든 그 재료가 될 소체가 필요해.","JPN":"融合体を作るには、とにかくその材料になる素体が必要なんだ。","ENG":"To create hybriders, you need bodies to serve as the hosts.","TWN":"想要製造融合體，簡單來說，就是需要原料。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"말했듯이 성공적으로 융합할 확률은 그다지 높지 않으니까 많으면 많을수록 좋겠지.","JPN":"すでに言った通り、融合に成功する確率はそこまで高くない。多ければ多いほど良いということだ。","ENG":"And since the chance of success isn't very high, it's always better to have more samples.","TWN":"正如我提到的，成功融合的機率不是很高，所以原料越多越好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이번처럼 도시 하나를 통째로 써먹을 수 있다면 더 바랄 나위가 없을 테고.","JPN":"今回のように一都市を丸々掌握できれば、もう言うことなしだな。","ENG":"And it can't get any better than having an entire city at their disposal.","TWN":"如果能像這次一樣用上一整個城市，對他們而言可說是求之不得。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"세, 세상에...... 그럼 대피소로 사람들을 모으던 게.......","JPN":"そ、そんな……じゃあ、避難所に人々を集結させていたのは……","ENG":"Good lord... Then is that why they were rounding up people in the shelters...?","TWN":"天、天哪……他們把大家聚集到避難所裡去……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"시민들을 지키기 위해서가 아니라 개조 대상으로 써먹으려는 거였군요.","JPN":"市民を守るためではなく、改造対象として使うためだったのですね。","ENG":"It wasn't to protect the citizens... They were going to use them to create hybriders...","TWN":"不是為了守護市民，而是為了改造……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 딱히 이번이 처음도 아니야.","JPN":"そうだ。今に始まったことでもない。","ENG":"Yup. This isn't the first time they've done this either.","TWN":"沒錯，而且這也不是他們第一次這樣做了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"물론 이 정도로 큰 도시에 손길을 뻗은 건 처음이지만, 작은 마을 정도는 벌써 몇 개나 흔적도 없이 잡아먹은 것 같더군.","JPN":"もちろん、今回ほどの大都市に魔の手を伸ばしたのは始めてだが、小さな町くらいはすでにいくつも跡形もなく飲み込んでしまったようだ。","ENG":"Of course, they haven't tried it with a city this big till now, but they've already wiped out a few small towns without leaving a trace.","TWN":"當然，這是他們第一次向這麼大的城市下手，但其他小村莊已經被他們榨乾好幾個了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어, 엄청 나쁜 사람들이잖아요...... 그, 그런 짓을 하다니.......","JPN":"す、すごく悪い人たちじゃないですか……そ、そんなことをするなんて……","ENG":"These guys are so evil... How could they...","TWN":"天啊，真是壞透了……居然做出這種事來……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐......!","JPN":"ちょっと待って……！","ENG":"Wait...!","TWN":"等等！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 도시에 있는 사람들 전부 저 녀석들의 수술대에 올라간다는 거야?","JPN":"じゃあ、都市にいる人たち全員がそいつらの手術台に上げられるということ？","ENG":"Does that mean they'll do that to everyone in the city?","TWN":"那在城裡的人，都已經上了他們的手術臺了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"벼, 병원에 있는 사람들도?","JPN":"びょ、病院の人たちも？","ENG":"Even the people in...the h-hospital?","TWN":"連，連醫院裡的人們都已經……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그렇게 되겠지. 이대로 내버려 둔다면.","JPN":"……いずれはそうなるだろう。このまま放っておくとな。","ENG":"...I believe so. If we don't do anything about it.","TWN":"……再這樣放任下去，應該會變成這樣吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"특히 이 도시에 있는 침식재난 구호 병원은 녀석들에게 크리스마스 선물이나 마찬가지야.","JPN":"とくにこの都市にいる侵食災害救護病院は、奴らにとってはクリスマスプレゼントのようなもんだ。","ENG":"The corruption disaster relief hospital in the city is practically a Christmas present for these guys.","TWN":"特別是這個都市的侵蝕災難救護醫院，對這些傢伙來說，無異於一份聖誕大禮。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"장비에, 약물에, 침식이 진행되고 있는 시술 대상까지 예쁘게 포장되어 있으니까.","JPN":"装備や薬物、侵食が進んでいる施術対象まで、すべて詰め合わせになっているからな。","ENG":"They have equipment, drugs, and people who are already going through the corruption process all in one spot.","TWN":"因為醫療裝備、藥物，還有正在進行侵蝕手術的病人，都像是被包裝得漂漂亮亮的禮物盒。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"놈들이 그냥 지나칠 리 없어.","JPN":"奴らがそのまま放っておくわけがない。","ENG":"There's no way they'll leave it alone.","TWN":"他們是不會輕易放過的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......도, 돌아가야 해!","JPN":"……も、戻らなきゃ！","ENG":"We... We have to go back!","TWN":"……我、我們得回去！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당장!","JPN":"今すぐに！","ENG":"Right now!","TWN":"現在！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"미, 미나야? 무슨 소릴 하는 거야?","JPN":"ミ、ミナちゃん？　何言ってるの？","ENG":"M-Mina? What are you talking about?","TWN":"米、米娜？妳知道妳在說什麼嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"너도 들었잖아? 거긴 지금 호랑이 입 속이나 다름없어! 위험하다고!","JPN":"君も聞いたよね？　今そこは猛獣の巣窟みたいなもんだよ！　危険すぎるよ！","ENG":"You heard him! We'll be walking into the eye of the storm! It's dangerous!","TWN":"妳不是也聽到了嗎？ 回那邊就跟進到在老虎的嘴裡沒什麼兩樣，很危險的！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 건 아무래도 좋아! 난 돌아가야 해!","JPN":"そんなのどうでもいい！　私は戻らなきゃならないの！","ENG":"I don't care! I have to go back!","TWN":"那種事怎麼樣都好，我得回去才行！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"도와주지 않겠다면, 나 혼자서라도.......","JPN":"手伝ってくれないなら、私ひとりでも……","ENG":"If you won't help me, I'll go by myself...","TWN":"你們不幫忙就算了，我一個人也可以……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_QM","text":{"KOREA":"찾았다. 쥐새끼들.","JPN":"見つけた、ネズミども。","ENG":"I found you. You little rats.","TWN":"哟，老鼠們。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_QM","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야?!","JPN":"な、なに！？","ENG":"W-what?","TWN":"什、什麼！？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};